interface UserSettings {
  // Subscription & API
  userTier: 'free' | 'pro';
  openRouterApiKey?: string;
  byokApiKey?: string;

  // UI Preferences
  theme: 'dark' | 'light';
  autoSave: boolean;
  showHints: boolean;

  // Generation Settings
  defaultDesignSystem: string;
  preferredModel?: string;
  generationQuality: 'fast' | 'balanced' | 'quality';

  // Canvas Settings
  gridEnabled: boolean;
  snapToGrid: boolean;
  defaultZoom: number;
}

class SettingsService {
  private settings: UserSettings = {
    userTier: 'free',
    theme: 'dark',
    autoSave: true,
    showHints: true,
    defaultDesignSystem: 'No design system',
    generationQuality: 'balanced',
    gridEnabled: true,
    snapToGrid: false,
    defaultZoom: 100
  };

  private readonly STORAGE_KEY = 'magicpath_settings';

  constructor() {
    this.loadSettings();
  }

  // Load settings from localStorage
  private loadSettings() {
    try {
      const stored = localStorage.getItem(this.STORAGE_KEY);
      if (stored) {
        const parsed = JSON.parse(stored);
        this.settings = { ...this.settings, ...parsed };
      }
    } catch (error) {
      console.error('Failed to load settings:', error);
    }
  }

  // Save settings to localStorage
  private saveSettings() {
    try {
      localStorage.setItem(this.STORAGE_KEY, JSON.stringify(this.settings));
    } catch (error) {
      console.error('Failed to save settings:', error);
    }
  }

  // Get all settings
  getSettings(): UserSettings {
    return { ...this.settings };
  }

  // Update specific setting
  updateSetting<K extends keyof UserSettings>(key: K, value: UserSettings[K]) {
    this.settings[key] = value;
    this.saveSettings();

    // Trigger settings change event
    window.dispatchEvent(new CustomEvent('settingsChanged', {
      detail: { key, value, settings: this.getSettings() }
    }));
  }

  // Update multiple settings at once
  updateSettings(updates: Partial<UserSettings>) {
    Object.entries(updates).forEach(([key, value]) => {
      (this.settings as any)[key] = value;
    });
    this.saveSettings();

    window.dispatchEvent(new CustomEvent('settingsChanged', {
      detail: { settings: this.getSettings() }
    }));
  }

  // API Key Management
  setOpenRouterKey(apiKey: string) {
    this.updateSetting('openRouterApiKey', apiKey);
  }

  setBYOKKey(apiKey: string) {
    this.updateSetting('byokApiKey', apiKey);
  }

  clearApiKeys() {
    this.updateSettings({
      openRouterApiKey: undefined,
      byokApiKey: undefined
    });
  }

  // Subscription Management
  upgradeToPro() {
    this.updateSetting('userTier', 'pro');
  }

  downgradeToDemoMode() {
    this.updateSettings({
      userTier: 'free',
      openRouterApiKey: undefined
    });
  }

  // Feature Access Checks
  canAccessProFeatures(): boolean {
    return this.settings.userTier === 'pro';
  }

  hasValidApiKey(): boolean {
    return !!(this.settings.openRouterApiKey || this.settings.byokApiKey);
  }

  getApiKeyStatus(): {
    hasOpenRouter: boolean;
    hasBYOK: boolean;
    canGenerate: boolean;
  } {
    return {
      hasOpenRouter: !!this.settings.openRouterApiKey,
      hasBYOK: !!this.settings.byokApiKey,
      canGenerate: this.settings.userTier === 'free' || this.hasValidApiKey()
    };
  }

  // Export/Import Settings
  exportSettings(): string {
    const exportData = { ...this.settings };
    // Remove sensitive data from export
    delete exportData.openRouterApiKey;
    delete exportData.byokApiKey;

    return JSON.stringify(exportData, null, 2);
  }

  importSettings(settingsJson: string): boolean {
    try {
      const imported = JSON.parse(settingsJson);

      // Validate imported settings
      const validKeys = Object.keys(this.settings);
      const filteredImport = Object.fromEntries(
        Object.entries(imported).filter(([key]) => validKeys.includes(key))
      );

      // Don't import API keys for security
      delete filteredImport.openRouterApiKey;
      delete filteredImport.byokApiKey;

      this.updateSettings(filteredImport);
      return true;
    } catch (error) {
      console.error('Failed to import settings:', error);
      return false;
    }
  }

  // Reset to defaults
  resetToDefaults() {
    const defaultSettings: UserSettings = {
      userTier: 'free',
      theme: 'dark',
      autoSave: true,
      showHints: true,
      defaultDesignSystem: 'No design system',
      generationQuality: 'balanced',
      gridEnabled: true,
      snapToGrid: false,
      defaultZoom: 100
    };

    this.settings = defaultSettings;
    this.saveSettings();

    window.dispatchEvent(new CustomEvent('settingsChanged', {
      detail: { settings: this.getSettings() }
    }));
  }

  // Usage Analytics (for billing/limits)
  getUsageStats(): {
    componentsGenerated: number;
    lastUsageReset: string;
    freeGenerationsLeft: number;
  } {
    const stored = localStorage.getItem('magicpath_usage');
    const defaultStats = {
      componentsGenerated: 0,
      lastUsageReset: new Date().toISOString(),
      freeGenerationsLeft: 50 // Free tier limit
    };

    if (!stored) return defaultStats;

    try {
      const parsed = JSON.parse(stored);
      return { ...defaultStats, ...parsed };
    } catch {
      return defaultStats;
    }
  }

  incrementUsage() {
    const stats = this.getUsageStats();
    stats.componentsGenerated += 1;

    if (this.settings.userTier === 'free') {
      stats.freeGenerationsLeft = Math.max(0, stats.freeGenerationsLeft - 1);
    }

    localStorage.setItem('magicpath_usage', JSON.stringify(stats));
  }

  resetUsageStats() {
    const stats = {
      componentsGenerated: 0,
      lastUsageReset: new Date().toISOString(),
      freeGenerationsLeft: 50
    };
    localStorage.setItem('magicpath_usage', JSON.stringify(stats));
  }
}

export const settingsService = new SettingsService();
export type { UserSettings };
